module top_module(
	input [31:0] inALUOut,
	input reset, clk,
	output [31:0] outALUOut
    );reg [31:0] unused_registerALUOut;

	assign outALUOut = unused_registerALUOut;

	always@(posedge clk)
		begin
			if (reset)
				begin
					unused_registerALUOut <= 32'b0;
				end
			else
				begin
					unused_registerALUOut <= inALUOut;
				end
		end

endmodule
